import { ipcMain } from 'electron';
import * as net from 'net';
import {
  IPC_CHANNELS,
  TunnelOpenSchema,
  TunnelCloseSchema,
  TunnelStatusSchema,
  ApiResult,
} from './types';
import { sshService } from '../services/SSHService';

interface ActiveTunnel {
  serverId: string;
  localPort: number;
  remoteHost: string;
  remotePort: number;
  server: net.Server;
  connections: Set<net.Socket>;
}

// Map of "serverId:localPort" -> ActiveTunnel
const activeTunnels = new Map<string, ActiveTunnel>();

function tunnelKey(serverId: string, localPort: number): string {
  return `${serverId}:${localPort}`;
}

export function registerTunnelHandlers() {
  // tunnel:open — create a local TCP server that forwards to remote via SSH
  ipcMain.handle(
    IPC_CHANNELS.TUNNEL_OPEN,
    async (
      _event,
      input
    ): Promise<ApiResult<{ localPort: number }>> => {
      try {
        const { serverId, remoteHost, remotePort, localPort: requestedPort } =
          TunnelOpenSchema.parse(input);

        // If a specific port was requested and is already tunneled, return it
        if (requestedPort > 0) {
          const key = tunnelKey(serverId, requestedPort);
          if (activeTunnels.has(key)) {
            return { success: true, data: { localPort: requestedPort } };
          }
        }

        // Establish/reuse SSH connection (handles reconnect automatically)
        const sshClient = await sshService.connect(serverId);

        const connections = new Set<net.Socket>();

        const server = net.createServer((socket) => {
          connections.add(socket);
          socket.on('close', () => connections.delete(socket));

          sshClient.forwardOut(
            '127.0.0.1',
            socket.localPort || 0,
            remoteHost,
            remotePort,
            (err, stream) => {
              if (err) {
                socket.end();
                connections.delete(socket);
                return;
              }
              stream.on('error', () => {
                socket.destroy();
                connections.delete(socket);
              });
              socket.on('error', () => {
                stream.destroy();
                connections.delete(socket);
              });
              socket.pipe(stream).pipe(socket);
              stream.on('close', () => {
                socket.end();
                connections.delete(socket);
              });
            }
          );
        });

        // Listen on requested port, or 0 for OS auto-assign
        await new Promise<void>((resolve, reject) => {
          server.on('error', reject);
          server.listen(requestedPort, '127.0.0.1', () => resolve());
        });

        // Get the actual bound port (important when requestedPort was 0)
        const boundPort = (server.address() as net.AddressInfo).port;
        const key = tunnelKey(serverId, boundPort);

        activeTunnels.set(key, {
          serverId,
          localPort: boundPort,
          remoteHost,
          remotePort,
          server,
          connections,
        });

        console.log(
          `[Tunnel] Opened tunnel localhost:${boundPort} -> ${remoteHost}:${remotePort} (server ${serverId})`
        );

        return { success: true, data: { localPort: boundPort } };
      } catch (error: any) {
        console.error('[Tunnel] Failed to open tunnel:', error);
        return {
          success: false,
          error: error.message || 'Failed to open tunnel',
        };
      }
    }
  );

  // tunnel:close — tear down a tunnel
  ipcMain.handle(
    IPC_CHANNELS.TUNNEL_CLOSE,
    async (_event, input): Promise<ApiResult<void>> => {
      try {
        const { serverId, localPort } = TunnelCloseSchema.parse(input);
        const key = tunnelKey(serverId, localPort);
        const tunnel = activeTunnels.get(key);

        if (!tunnel) {
          return { success: true, data: undefined };
        }

        // Close all active socket connections
        for (const socket of tunnel.connections) {
          socket.destroy();
        }
        tunnel.connections.clear();

        // Close the TCP server
        await new Promise<void>((resolve) =>
          tunnel.server.close(() => resolve())
        );
        activeTunnels.delete(key);

        console.log(
          `[Tunnel] Closed tunnel localhost:${localPort} (server ${serverId})`
        );

        return { success: true, data: undefined };
      } catch (error: any) {
        console.error('[Tunnel] Failed to close tunnel:', error);
        return {
          success: false,
          error: error.message || 'Failed to close tunnel',
        };
      }
    }
  );

  // tunnel:status — check active tunnels for a server
  ipcMain.handle(
    IPC_CHANNELS.TUNNEL_STATUS,
    async (
      _event,
      input
    ): Promise<
      ApiResult<{
        tunnels: {
          localPort: number;
          remoteHost: string;
          remotePort: number;
        }[];
      }>
    > => {
      try {
        const { serverId } = TunnelStatusSchema.parse(input);
        const tunnels: {
          localPort: number;
          remoteHost: string;
          remotePort: number;
        }[] = [];

        for (const [, tunnel] of activeTunnels) {
          if (tunnel.serverId === serverId) {
            tunnels.push({
              localPort: tunnel.localPort,
              remoteHost: tunnel.remoteHost,
              remotePort: tunnel.remotePort,
            });
          }
        }

        return { success: true, data: { tunnels } };
      } catch (error: any) {
        return {
          success: false,
          error: error.message || 'Failed to get tunnel status',
        };
      }
    }
  );

  // tunnel:list — list all active tunnels across all servers
  ipcMain.handle(
    IPC_CHANNELS.TUNNEL_LIST,
    async (): Promise<
      ApiResult<{
        tunnels: {
          serverId: string;
          localPort: number;
          remoteHost: string;
          remotePort: number;
        }[];
      }>
    > => {
      const tunnels = Array.from(activeTunnels.values()).map((t) => ({
        serverId: t.serverId,
        localPort: t.localPort,
        remoteHost: t.remoteHost,
        remotePort: t.remotePort,
      }));
      return { success: true, data: { tunnels } };
    }
  );
}

/**
 * Close all active tunnels. Called on app quit.
 */
export function closeAllTunnels() {
  for (const [key, tunnel] of activeTunnels) {
    for (const socket of tunnel.connections) {
      socket.destroy();
    }
    tunnel.server.close();
    activeTunnels.delete(key);
  }
  console.log('[Tunnel] All tunnels closed');
}
